"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[1313],{42875(e,n,i){i.r(n),i.d(n,{assets:()=>d,contentTitle:()=>u,default:()=>h,frontMatter:()=>a,metadata:()=>r,toc:()=>l});const r=JSON.parse('{"id":"learning/courses/integrating-quantum-and-high-performance-computing/next-steps","title":"N\xe4chste Schritte","description":"Diese Lektion untersucht den aktuellen Stand des Quantencomputings und wie die Forschungsgemeinschaft den Quantenvorteil anstrebt.","source":"@site/i18n/de/docusaurus-plugin-content-docs/current/learning/courses/integrating-quantum-and-high-performance-computing/next-steps.mdx","sourceDirName":"learning/courses/integrating-quantum-and-high-performance-computing","slug":"/learning/courses/integrating-quantum-and-high-performance-computing/next-steps","permalink":"/learning/courses/integrating-quantum-and-high-performance-computing/next-steps","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/integrating-quantum-and-high-performance-computing/next-steps.mdx","tags":[],"version":"current","frontMatter":{"title":"N\xe4chste Schritte","sidebar_label":"N\xe4chste Schritte","description":"Diese Lektion untersucht den aktuellen Stand des Quantencomputings und wie die Forschungsgemeinschaft den Quantenvorteil anstrebt.","notebook_path":"learning/courses/integrating-quantum-and-high-performance-computing/next-steps.ipynb"},"sidebar":"tutorialsSidebar","previous":{"title":"SQD und SKQD","permalink":"/learning/courses/integrating-quantum-and-high-performance-computing/sqd-skqd"},"next":{"title":"Pr\xfcfung | Integration von Quantencomputing und Hochleistungsrechnen","permalink":"/learning/courses/integrating-quantum-and-high-performance-computing/exam"}}');var t=i(74848),s=i(28453);const a={title:"N\xe4chste Schritte",sidebar_label:"N\xe4chste Schritte",description:"Diese Lektion untersucht den aktuellen Stand des Quantencomputings und wie die Forschungsgemeinschaft den Quantenvorteil anstrebt.",notebook_path:"learning/courses/integrating-quantum-and-high-performance-computing/next-steps.ipynb"},u="Ausblick und k\xfcnftige Richtung {#future-outlook-and-direction}",d={},l=[{value:"Warum jetzt?",id:"why-now",level:3},{value:"5.1 Das gro\xdfe Bild",id:"the-big-picture",level:2},{value:"Gro\xdfe Ideen",id:"big-ideas",level:2},{value:"IBMs Ausblick f\xfcr die Zukunft",id:"ibms-outlook-for-the-future",level:2},{value:"Zusammenfassung",id:"summary",level:2}];function o(e){const n={a:"a",h1:"h1",h2:"h2",h3:"h3",header:"header",img:"img",li:"li",p:"p",ul:"ul",...(0,s.R)(),...e.components};return(0,t.jsxs)(t.Fragment,{children:["\n","\n",(0,t.jsx)(n.header,{children:(0,t.jsx)(n.h1,{id:"future-outlook-and-direction",children:"Ausblick und k\xfcnftige Richtung"})}),"\n",(0,t.jsx)(n.p,{children:"Bisher haben wir uns mit der Motivation besch\xe4ftigt, warum Hochleistungsrechnen (HPC) und Quantencomputing gemeinsam zur L\xf6sung wissenschaftlicher Probleme eingesetzt werden. Wir haben klassische und Quantenrechenressourcen definiert \u2013 darunter CPUs, GPUs und QPUs \u2013 und erl\xe4utert, wie man sie mithilfe von Techniken wie vertikaler und horizontaler Skalierung, Scheduling und Workload-Management skaliert und verwaltet. Dar\xfcber hinaus haben wir Programmiermodelle sowohl f\xfcr QPUs (z. B. Quantum Circuits und Primitiven wie Sampler und Estimator) als auch f\xfcr klassische Computer erkundet, einschlie\xdflich paralleler Programmierpraktiken mit MPI \u2013 einem leistungsstarken Werkzeug im heterogenen Quantenklassischen Computing. Schlie\xdflich haben wir fortgeschrittene quanten-sampling-basierte Algorithmen studiert und angewandt, etwa Sample-based Quantum Diagonalization (SQD) und Sample-based Krylov Quantum Diagonalization (SKQD). Diese Algorithmen nutzen die Unterraummethode, um die Grundzustandsenergie von Molek\xfclen und Materialien pr\xe4zise zu sch\xe4tzen, indem Quantenzust\xe4nde pr\xe4pariert und abgetastet werden, die einen Unterraum f\xfcr die klassische Diagonalisierung definieren \u2013 eine Kombination verschiedener Programmiermodelle auf einem Satz heterogener Ressourcen. Mit diesen grundlegenden Konzepten des Quanten- und klassischen Supercomputings reden wir nicht mehr davon, dass das eine das andere ersetzt, sondern davon, ein leistungsstarkes, integriertes System zu schaffen, das synergetisch zusammenarbeitet \u2013 eine Kombination, die den Beginn des Quantenvorteils einl\xe4uten soll."}),"\n",(0,t.jsx)(n.h3,{id:"why-now",children:"Warum jetzt?"}),"\n",(0,t.jsxs)(n.p,{children:['Die Gemeinschaft hat den Meilenstein der \u201eQuantenn\xfctzlichkeit" bereits hinter sich gelassen \u2013 also den Zeitpunkt, an dem Quantencomputer erstmals als n\xfctzliche wissenschaftliche Werkzeuge nachgewiesen wurden, die Berechnungen jenseits klassischer Brute-Force-Simulationen erm\xf6glichen. Diese N\xfctzlichkeits\xe4ra begann mit dem viel beachteten ',(0,t.jsx)(n.a,{href:"https://www.nature.com/articles/s41586-023-06096-3",children:"Utility-Paper"}),', das 2023 auf dem Cover von Nature erschien, und umfasste dutzende Publikationen von Partnern, Kunden und Forschenden bei IBM Quantum\xae. Heute hat sich der Fokus auf die n\xe4chste entscheidende Herausforderung verlagert: das Erreichen des Quantenvorteils. Lange Zeit litt der Begriff \u201eQuantenvorteil" unter unpr\xe4zisen Definitionen. Dieses ',(0,t.jsx)(n.a,{href:"https://arxiv.org/abs/2506.20658",children:"Paper"})," hat eine konkrete Definition vorgeschlagen, die wir hier verwenden. Demnach bezeichnet Quantenvorteil die Ausf\xfchrung einer Informationsverarbeitungsaufgabe auf Quantenhardware, die zwei wesentliche Kriterien erf\xfcllt:"]}),"\n",(0,t.jsx)(n.p,{children:"i) Die Korrektheit des Ergebnisses kann streng nachgewiesen werden, und"}),"\n",(0,t.jsx)(n.p,{children:"ii) Die Aufgabe wird mit einer Quanten\xfcberlegenheit ausgef\xfchrt, die nachweislich eine h\xf6here Effizienz, Kosteneffektivit\xe4t oder Genauigkeit bietet, als mit klassischer Berechnung allein erreichbar w\xe4re."}),"\n",(0,t.jsx)(n.p,{children:"Es wird erwartet, dass der Quantenvorteil bis Ende 2026 erstmals auftreten wird und dass dies durch die gemeinsame Nutzung von Quanten- und HPC-Ressourcen geschehen wird. Diese Lektion skizziert die Kernvision f\xfcr dieses neue Paradigma, erl\xe4utert die wichtigsten Ideen und gibt einen Ausblick, der auf einem verifizierbaren, plattformunabh\xe4ngigen Framework f\xfcr den Nachweis und die Realisierung eines echten Quantenvorteils beruht."}),"\n",(0,t.jsx)(n.h2,{id:"the-big-picture",children:"5.1 Das gro\xdfe Bild"}),"\n",(0,t.jsx)(n.p,{children:'Zum ersten Mal erleben wir einen bedeutenden Wendepunkt in der Geschichte des Rechnens \u2013 die \xc4ra des quantenzentrierten Supercomputings (QCSC), ein aufkommendes Paradigma, das Quantenprozessoren (QPUs) eng mit klassischen Supercomputern integriert. Die Vision ist nicht, dass Quantensysteme klassische ersetzen, sondern zu demonstrieren, dass diese heterogene Architektur \u2013 bei der \u201eQuanten plus Klassik" die rein klassische Berechnung \xfcbertrifft \u2013 der wirkungsvollste Weg nach vorn ist. In diesem Modell sind QPUs als spezialisierte Co-Prozessoren gedacht, die Seite an Seite mit CPUs und GPUs arbeiten, um Rechenproblemen zu bew\xe4ltigen, die f\xfcr klassische Computer unl\xf6sbar sind.'}),"\n",(0,t.jsx)(n.p,{children:"Das volle Potenzial dieser neuen Architektur kann nur ausgesch\xf6pft werden, indem diese leistungsstarken Werkzeuge so vielen Nutzenden wie m\xf6glich zug\xe4nglich gemacht werden. Diese Vision nimmt bereits Gestalt an: durch den Einsatz von Quantensystemen in etablierten Hochleistungsrechenzentren und die Entwicklung von Software wie Quantum-Slurm-Plugins, die ihre Integration in bestehende klassische Workflows vereinfacht. Indem diese heterogenen Systeme f\xfcr die breitere Forschungsgemeinschaft zug\xe4nglicher gemacht werden, f\xf6rdern wir das Umfeld, das f\xfcr Innovation und Entdeckung notwendig ist."}),"\n",(0,t.jsx)(n.p,{children:"Diese Strategie \u2013 integrierte Technologie kombiniert mit einer breiten Nutzerbasis \u2013 ist der Weg, auf dem die Gemeinschaft in naher Zukunft den Quantenvorteil erreichen wird. Der Quantenvorteil ist kein einzelner, endg\xfcltiger Meilenstein, sondern ein Prozess \u2013 eine Folge von immer belastbareren Demonstrationen, die von der Gemeinschaft genau gepr\xfcft, reproduziert und in Frage gestellt werden, bis ein wissenschaftlicher Konsens erreicht ist. Dies ist der Weg, um bis Ende 2026 die ersten glaubw\xfcrdigen und verifizierbaren F\xe4lle zu zeigen, in denen diese neue Art des Rechnens praktische Probleme effizienter, kosteng\xfcnstiger oder genauer l\xf6st, als es mit klassischer Berechnung allein m\xf6glich w\xe4re."}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"Ein Diagramm, das die Kosten von Simulationen als Funktion zunehmender Schaltkreiskomplexit\xe4t f\xfcr klassische Computer und Quantencomputer mit Fehlerminderung zeigt. Sobald sich die Kurven schneiden, entspricht der Bereich zwischen ihnen dem Quantenvorteil.",src:i(89816).A+"",width:"793",height:"540"})}),"\n",(0,t.jsx)(n.h2,{id:"big-ideas",children:"Gro\xdfe Ideen"}),"\n",(0,t.jsx)(n.p,{children:"Um diese Vision zu verwirklichen, m\xfcssen mehrere entscheidende Fragen und Ideen angegangen werden."}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsx)(n.p,{children:"Optimale Workload-Partitionierung: Auf der Software-Seite liegt die Herausforderung in der Verwaltung komplexer hybrider Workflows. Die reibungslose Orchestrierung von Aufgaben \xfcber Quanten- und klassische Ressourcen hinweg erfordert ausgefeilte Werkzeuge. Dazu geh\xf6ren Quantum-HPC-Middleware und Runtime-Infrastrukturen, die f\xfcr Job-Scheduling, Ressourcenverwaltung und Datenfluss in dieser heterogenen Umgebung ausgelegt sind. Dar\xfcber hinaus ist die Entwicklung von Techniken zur effektiven Parallelisierung von Quantenschaltkreisen oder deren Zerlegung in kleinere, handhabbare Teile entscheidend, um den Nutzen der heutigen Quantenhardware zu maximieren."}),"\n"]}),"\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsx)(n.p,{children:'Fehlertoleranz auf Systemebene: Die ultimative L\xf6sung zum Schutz von Quanteninformation vor Rauschen ist die fehlertolerante Quantenberechnung (FTQC), bei der Information in robuste \u201elogische Qubits" kodiert wird. Obwohl neue Quantum-Low-Density-Parity-Check-Codes (qLDPC) einen Weg bieten, den enormen Ressourcenaufwand zu reduzieren, ist die Implementierung vollst\xe4ndiger Fehlertoleranz im unmittelbaren Nahbereich noch nicht realisierbar. Gleichzeitig nutzt Fehlerminderung klassische Nachverarbeitung, um Verzerrungen in Berechnungen durch Rauschen zu reduzieren oder zu eliminieren \u2013 ebenfalls ein kritisches Element beim Erreichen fehlertoleranter Quantensysteme auf Systemebene. Leistungsstarke Fehlerminderungsmethoden werden bereits als Dienst eingesetzt und demonstrieren die St\xe4rke der QCSC-Architektur. Zum Beispiel:'}),"\n",(0,t.jsxs)(n.ul,{children:["\n",(0,t.jsxs)(n.li,{children:["Algorithmiq's ",(0,t.jsx)(n.a,{href:"/guides/algorithmiq-tem",children:"Tensor Network Error Mitigation"})," (TEM) behandelt Rauschen in der Software-Nachverarbeitung und nutzt klassische HPC-Ressourcen, um die Reichweite aktueller QPUs zu erweitern."]}),"\n",(0,t.jsxs)(n.li,{children:["Qedma's ",(0,t.jsx)(n.a,{href:"/guides/qedma-qesem",children:"Quantum Error Suppression and Error Mitigation"})," (QESEM) kombiniert Fehlerunterdr\xfcckung auf Hardware-Ebene mit Fehlerminderung, um die Zuverl\xe4ssigkeit von Quantenberechnungen in gro\xdfem Ma\xdfstab zu verbessern."]}),"\n"]}),"\n"]}),"\n",(0,t.jsxs)(n.li,{children:["\n",(0,t.jsx)(n.p,{children:"Demokratisierung des Zugangs: Diese leistungsstarken hybriden Systeme einem breiten Publikum zug\xe4nglich zu machen, ist der Schl\xfcssel zur Beschleunigung von Innovation. Dies wird bereits durch die physische Installation von Quantensystemen in HPC-Zentren und die Ver\xf6ffentlichung von Slurm-Plugins f\xfcr eine reibungslose Integration verwirklicht. Um diese Integration zu vereinfachen, haben beide Unternehmen Slurm-Plugins ver\xf6ffentlicht, damit Quanten-Workloads mit Standard-HPC-Schedulern verwaltet werden k\xf6nnen. Dar\xfcber hinaus bieten umfassende Software-Stacks wie Qiskit eine cloudbasierte Runtime-Umgebung f\xfcr die Ausf\xfchrung von Quantenschaltkreisen mit geringer Latenz, die komplexe hybride Aufgaben orchestriert und Werkzeuge f\xfcr Kompilierung, Optimierung und Fehlerminderung bereitstellt. Offener Zugang zu Quantenhardware und quelloffen entwickelte Softwarepakete werden dabei zweifellos eine entscheidende Rolle spielen."}),"\n"]}),"\n"]}),"\n",(0,t.jsx)(n.h2,{id:"ibms-outlook-for-the-future",children:"IBMs Ausblick f\xfcr die Zukunft"}),"\n",(0,t.jsxs)(n.p,{children:["Die ",(0,t.jsx)(n.a,{href:"https://www.ibm.com/quantum/hardware#roadmap",children:"IBM Quantum Development Roadmap"})," veranschaulicht dieses gro\xdfe Bild und diese gro\xdfen Ideen gut."]}),"\n",(0,t.jsx)(n.p,{children:(0,t.jsx)(n.img,{alt:"Die IBM Quantum Development Roadmap",src:i(97895).A+"",width:"960",height:"536"})}),"\n",(0,t.jsx)(n.p,{children:'IBMs Hardware-Roadmap f\xfcr Quantencomputing wird durch den Fokus auf mehr Qubit-Skalierung und bessere Konnektivit\xe4t vorangetrieben. Die Nighthawk-Serie (2025\u20132028) nutzt eine neue quadratische Gitterarchitektur zur Verbesserung der Konnektivit\xe4t, w\xe4hrend der Loon-Prozessor (2025) \u201ec-Koppler" einf\xfchrt, um nicht-lokale Qubit-Konnektivit\xe4t zu erm\xf6glichen \u2013 entscheidend f\xfcr fehlertolerantes Quantencomputing (FTQC). Diese Roadmap m\xfcndet in den Systemen IBM Quantum Starling (2029) und Blue Jay (2033+), die f\xfcr gro\xdf angelegte, fehlertolerante Berechnungen mit Millionen von Gates und Tausenden logischer Qubits ausgelegt sind.'}),"\n",(0,t.jsx)(n.p,{children:"Die Software- und Middleware-Strategie baut auf vier Kernzielen auf: pr\xe4zise Ausf\xfchrung, Orchestrierung von Workloads, Entdeckung neuer Algorithmen und deren Anwendung auf spezifische Anwendungsf\xe4lle. Die Roadmap umfasst laufende Verbesserungen wie dynamische Schaltkreise im Utility-Ma\xdfstab (2025) und neue Profiling-Werkzeuge (2026) f\xfcr eine effiziente Ausf\xfchrung. F\xfcr die Workload-Orchestrierung werden die C-API (2025) und k\xfcnftige Workflow-Beschleuniger (2027) Quantencomputing und klassisches Hochleistungsrechnen (HPC) integrieren. Dar\xfcber hinaus wird IBM\xae Utility-Mapping-Werkzeuge (2026) und neue Schaltkreisbibliotheken (2029) einf\xfchren, um die Entdeckung und Anwendung neuer Algorithmen zu erleichtern."}),"\n",(0,t.jsx)(n.h2,{id:"summary",children:"Zusammenfassung"}),"\n",(0,t.jsx)(n.p,{children:"Wir haben das gro\xdfe Bild und die gro\xdfen Ideen hinter dem QCSC-Ziel erkundet und uns IBMs Roadmap f\xfcr die Entwicklung und Innovation im Quantencomputing angeschaut. Diese Reise ist, wie wir gesehen haben, ein Marathon, kein Sprint. Obwohl IBM sich verpflichtet hat, zunehmend leistungsf\xe4higere Quantencomputer zu liefern, ist unser Fortschritt nur ein Teil der Gleichung. Es ist entscheidend, dass die Quantengemeinschaft weiterhin neue Algorithmen entwickelt und so den Weg f\xfcr Anwendungen ebnet, die n\xfctzliches Quantencomputing wirklich in die Welt bringen."}),"\n",(0,t.jsx)(n.p,{children:"Um dies zu erreichen, m\xfcssen wir zusammenarbeiten. Das bedeutet, standardisierte Benchmarking-Probleme mithilfe klassischer Experten zu etablieren, um Relevanz und Fairness sicherzustellen. Es erfordert auch die Ver\xf6ffentlichung detaillierter Methoden und Datens\xe4tze zur Reproduzierbarkeit sowie die Pflege offener Leaderboards zur Verfolgung unseres kollektiven Fortschritts."}),"\n",(0,t.jsx)(n.p,{children:"Es war noch nie eine aufregendere Zeit, Teil dieser Gemeinschaft zu sein. Indem wir diese Best Practices annehmen und unsere Erkundungen fortsetzen, k\xf6nnen wir gemeinsam das volle Potenzial des Quantenvorteils verwirklichen."})]})}function h(e={}){const{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(o,{...e})}):o(e)}},89816(e,n,i){i.d(n,{A:()=>r});const r=i.p+"assets/images/advantage-f7fc7a67f0f1aac33e4c95b7965b10c0.svg"},97895(e,n,i){i.d(n,{A:()=>r});const r=i.p+"assets/images/roadmap-c4a476cff4c185739f3c99c69c717523.svg"},28453(e,n,i){i.d(n,{R:()=>a,x:()=>u});var r=i(96540);const t={},s=r.createContext(t);function a(e){const n=r.useContext(s);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function u(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(t):e.components||t:a(e.components),r.createElement(s.Provider,{value:n},e.children)}}}]);